using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Cosmos provider no longer supports HasIndex (throws at model validation).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve compatibility with existing documents that use "Discriminator".
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: Id property now maps directly to "id" in Cosmos (was "Blog|<key>").
        // Preserve the old composite format so existing documents are still found.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id).ToJsonProperty("id");
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

