arguments.new_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }

        // Breaking change 4: Cosmos provider now uses patch-based updates by default.
        // Full-document replace semantics changed; read-modify-write is fine here,
        // but be aware that only modified properties are sent (not the whole document).
        context.SaveChanges();
    }

    // Breaking change 5: Raw SQL using old discriminator column.
    // Queries like SELECT * FROM c WHERE c.Discriminator = 'Blog'
    // still work if HasDiscriminator("Discriminator") is configured (done in BlogContext).
    // If you had used $type (the new default), you'd need:
    //   SELECT * FROM c WHERE c["$type"] = 'Blog'
}

